INSERT INTO VST_VHCL_RSVT (
            VST_VHCL_RSVT_NO
          , VST_VHCL_TY_CD
          , VST_VHCL_NO
          , VSTR_NM
          , VST_YMD
          , VST_STTS_CD
          , REG_DT
          , VST_PRPS_CN
          , USER_NO
          , HO_NO
          , STAY_HR
) VALUES (
           'VSTRSVT_' || SEQ_VST_VHCL_RSVT.NEXTVAL
         , #{vstVhclTyCd}
         , #{vstVhclNo}
         , #{vstrNm}
         , #{vstYmd}
         , #{vstSttsCd}
         , SYSDATE
         , #{vstPrpsCn}
         , #{userNo}
         , #{hoNo}
         , #{stayHr}
         )

